/* Sombra y estilo del modal */
.modal-content {
  border-radius: 12px;
  box-shadow: 0 0 18px rgba(0, 0, 0, 0.12);
  border: 1px solid #dfe6ec;
}

.modal-footer{
  padding: 10px 15px 8px !important;
}



[selector = 'btn_preventivo']{
  margin-top: 20px !important;
  margin-right: 0px !important;
}



/* Contenedor general del nuevo modal */
[selector="contenido-modal-faltantes"] {
  padding: 22px 18px 0px;
  margin: -25px 0px -19px 0px;
  font-family: "Segoe UI", Roboto, sans-serif;
  background-color: #ffffff;
  color: #2c2c2c;
}

/* Ícono decorativo nuevo */
[selector="contenido-modal-faltantes"] .icono-documento::before {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f574"; /* fa-file-upload */
  font-size: 2.8rem;
  color: #dc3545; /* Rojo Bootstrap */
  display: inline-block;
  margin-bottom: -6px;
}

/* Título del modal */
[selector="contenido-modal-faltantes"] .titulo-faltantes {
  font-size: 1.3rem;
  font-weight: 600;
  color: #dc3545;
}

/* Texto principal */
[selector="contenido-modal-faltantes"] .texto-faltantes {
  font-size: 1.05rem;
  line-height: 1.6;
  color: #333333;
}

/* Texto secundario */
[selector="contenido-modal-faltantes"] .texto-faltantes-sub {
  font-size: 14px;
  padding-top: 5px;
}



/**/
[selector="banner-nota-no-emitidos"] {
  display: flex;
  align-items: center;
  background-color: #e9f4fc;
  border: 1px solid #b8daff;
  color: #0c5460;
  border-radius: 6px;
  padding: 10px 14px;
  font-size: 15px;
  font-family: "Segoe UI", Roboto, sans-serif;
  margin-bottom: 10px;
  margin-top: 20px;
}

[selector="banner-nota-no-emitidos"] .icono-alerta {
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f05a"; /* fa-info-circle */
  margin-right: 10px;
  font-size: 1.3rem;
  color: #17a2b8;
}
